                                  <tr key={t.id}>
                                      <td className="px-6 py-3 text-sm text-slate-600 dark:text-slate-300">{new Date(t.date).toLocaleDateString()}</td>
                                      <td className="px-6 py-3">
                                          <Badge color={t.type === 'income' ? 'green' : 'red'}>{t.type}</Badge>
