                <div className="flex justify-end pt-4 gap-2">
                    <Button type="button" variant="secondary" onClick={() => setIsRefundModalOpen(false)}>{t('cancel')}</Button>
                    <Button type="submit" variant="danger">Confirm Refund</Button>
                </div>
            </form>
